UPDATE Language_RU_RU
SET Text = 'Цитадель — это мощное укрепление, которое может быть построено только Великим Генералом. Вы можете построить Цитадель в любой точке своей территории.[NEWLINE][NEWLINE]При строительстве Цитадели границы вашей культуры расширятся, окружив Цитадель со всех сторон на один гекс. Если новая граница культуры захватывает гексы, уже принадлежащие другой цивилизации, вы понесете дипломатические последствия. Любой юнит, размещенный в Цитадели, получает бонус к оборонительной силе в размере 100%. Кроме того, любой вражеский юнит, который заканчивает свой ход рядом с Цитаделью, получает 30 урона (урон не суммируется с другими Цитаделями).[NEWLINE][NEWLINE] Акрополь в Афинах, Греция, является примером ранней мощной Цитадели. Такие сооружения было практически невозможно взять прямым штурмом, и они могли выдерживать длительные осады до своего падения.'
WHERE Tag = 'TXT_KEY_CIV5_IMPROVEMENTS_CITADEL_TEXT';
